import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Paper {
  id: string;
  title: string;
  journal: string;
  date: string;
  url?: string;
  abstract?: string;
  // AI Generated fields
  titleZh?: string;
  summary?: string;
  pico?: {
    p: string;
    i: string;
    c: string;
    o: string;
  };
  utility?: string;
  tags?: string[];
  isAnalyzed?: boolean;
}

export interface AnalysisResponse {
  titleZh: string;
  summary: string;
  pico: {
    p: string;
    i: string;
    c: string;
    o: string;
  };
  utility: string;
  tags: string[];
}

export enum Tab {
  FEED = 'FEED',
  ARCHITECTURE = 'ARCHITECTURE'
}

export enum JournalFilter {
  ALL = 'All Journals',
  NEJM = 'NEJM',
  JAMA_PSYCH = 'JAMA Psychiatry',
  LANCET_PSYCH = 'Lancet Psychiatry',
  AM_J_PSYCH = 'Am J Psychiatry',
  NATURE_NEURO = 'Nature Neuroscience'
}

export enum TopicFilter {
  ALL = 'All Topics',
  SCHIZOPHRENIA = 'Schizophrenia',
  DEPRESSION = 'Depression',
  BIPOLAR = 'Bipolar',
  ANXIETY = 'Anxiety',
  ADDICTION = 'Addiction',
  PSYCHOTHERAPY = 'Psychotherapy'
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Paper, AnalysisResponse } from "../types";

// Helper to get client (assumes user has selected key via window.aistudio or we use a provided one)
const getClient = () => {
  const apiKey = process.env.API_KEY; // In a real app, this comes from env. 
  // For this generated artifact, we rely on the injected process.env.API_KEY 
  // or the user interaction handles it in the main flow.
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

/**
 * Simulates the "Crawler" by using Google Search Grounding to find recent papers.
 */
export const fetchLatestPapers = async (topic: string, journal: string): Promise<Paper[]> => {
  const client = getClient();
  const query = `Find 3 most recent scientific research papers published in ${journal === 'All Journals' ? 'major psychiatry journals' : journal} about "${topic === 'All Topics' ? 'psychiatry' : topic}" published in the last month. Return their title, journal name, publication date, and a brief abstract/snippet.`;

  try {
    const response = await client.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: query,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    title: { type: Type.STRING },
                    journal: { type: Type.STRING },
                    date: { type: Type.STRING },
                    url: { type: Type.STRING, description: "The URL of the paper" },
                    abstract: { type: Type.STRING, description: "A brief summary or abstract text found" }
                },
                required: ["title", "journal", "date"]
            }
        }
      }
    });

    const text = response.text;
    if (!text) return [];

    const rawPapers = JSON.parse(text);

    // Transform into our Paper type
    return rawPapers.map((p: any, index: number) => ({
      id: `gen-${Date.now()}-${index}`,
      title: p.title,
      journal: p.journal,
      date: p.date,
      url: p.url || '#',
      abstract: p.abstract,
      isAnalyzed: false
    }));
  } catch (error) {
    console.error("Error fetching papers:", error);
    throw error;
  }
};

/**
 * Performs the deep PICO analysis and Translation on a specific paper.
 */
export const analyzePaperWithAI = async (paper: Paper): Promise<AnalysisResponse> => {
  const client = getClient();

  const prompt = `
    Analyze the following research paper abstract/title for a Psychiatrist.

    Title: ${paper.title}
    Abstract: ${paper.abstract || "No abstract provided, infer from title and common knowledge about this study if famous, otherwise state limitations."}

    Task:
    1. Translate the title to Traditional Chinese (Taiwan Medical Terminology).
    2. Summarize the key finding in one sentence (Chinese).
    3. Extract PICO (Population, Intervention, Comparison, Outcome) in English.
    4. Assess Clinical Utility (High/Medium/Low) and why (in Chinese).
    5. Generate 2-3 relevant tags.
  `;

  const response = await client.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          titleZh: { type: Type.STRING },
          summary: { type: Type.STRING },
          pico: {
            type: Type.OBJECT,
            properties: {
              p: { type: Type.STRING },
              i: { type: Type.STRING },
              c: { type: Type.STRING },
              o: { type: Type.STRING }
            }
          },
          utility: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No analysis generated");
  return JSON.parse(text) as AnalysisResponse;
};

