import React from 'react';
import { ARCHITECTURE_CONTENT } from '../constants';

// Simple markdown-like renderer for the content
export const ArchitectureInfo: React.FC = () => {
  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 md:p-8">
      <div className="prose prose-blue max-w-none">
        {ARCHITECTURE_CONTENT.split('\n').map((line, idx) => {
          if (line.startsWith('# ')) {
            return <h1 key={idx} className="text-2xl font-bold text-gray-900 mb-6 pb-2 border-b">{line.replace('# ', '')}</h1>;
          }
          if (line.startsWith('## ')) {
            return <h2 key={idx} className="text-xl font-bold text-gray-800 mt-8 mb-4">{line.replace('## ', '')}</h2>;
          }
          if (line.startsWith('**')) {
            // Very simple bold parsing for the demo
            return <p key={idx} className="mb-2 text-gray-800 font-semibold">{line.replace(/\*\*/g, '')}</p>;
          }
          if (line.startsWith('* ')) {
            return (
              <ul key={idx} className="list-disc list-inside ml-4 mb-2">
                <li className="text-gray-700">{line.replace('* ', '')}</li>
              </ul>
            );
          }
          if (line.startsWith('1.') || line.startsWith('2.') || line.startsWith('3.')) {
             return <p key={idx} className="mb-2 text-gray-700 ml-4 font-medium">{line}</p>
          }
          if (line.trim() === '') return <br key={idx} />;

          return <p key={idx} className="text-gray-600 mb-2 leading-relaxed">{line}</p>;
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { INITIAL_PAPERS } from './constants';
import { Paper, Tab, JournalFilter, TopicFilter } from './types';
import { PaperCard } from './components/PaperCard';
import { ArchitectureInfo } from './components/ArchitectureInfo';
import { fetchLatestPapers } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.FEED);
  const [papers, setPapers] = useState<Paper[]>(INITIAL_PAPERS);
  const [selectedTopic, setSelectedTopic] = useState<TopicFilter>(TopicFilter.ALL);
  const [selectedJournal, setSelectedJournal] = useState<JournalFilter>(JournalFilter.ALL);
  const [isFetching, setIsFetching] = useState(false);

  // Update a single paper in the list (e.g., after analysis)
  const handlePaperUpdate = (updatedPaper: Paper) => {
    setPapers(prev => prev.map(p => p.id === updatedPaper.id ? updatedPaper : p));
  };

  const handleRefresh = async () => {
    setIsFetching(true);
    try {
      // Use Gemini to 'crawl' live data
      const newPapers = await fetchLatestPapers(selectedTopic, selectedJournal);

      // Merge with existing papers (simple prepend for demo)
      setPapers(prev => [...newPapers, ...prev]);
    } catch (e) {
      alert("Failed to fetch new papers. Please ensure you have a valid API Key and quota.");
    } finally {
      setIsFetching(false);
    }
  };

  const currentDate = new Date().toLocaleDateString('zh-TW', { month: '2-digit', day: '2-digit' });

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between mb-4">
            <div>
              <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Psychiatry Brain</h1>
              <p className="text-xs text-gray-500 font-medium mt-1">AI-Powered Research Intelligence</p>
            </div>
            <div className="flex items-center gap-2 text-xs text-gray-500 bg-gray-100 px-3 py-1.5 rounded-full">
               <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
               Updated: {currentDate}
            </div>
          </div>

          {/* Navigation Tabs */}
          <div className="flex space-x-6 border-b border-gray-100">
            <button
              onClick={() => setActiveTab(Tab.FEED)}
              className={`pb-2 text-sm font-medium transition-colors border-b-2 ${
                activeTab === Tab.FEED
                  ? 'border-blue-600 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              Daily Feed
            </button>
            <button
              onClick={() => setActiveTab(Tab.ARCHITECTURE)}
              className={`pb-2 text-sm font-medium transition-colors border-b-2 ${
                activeTab === Tab.ARCHITECTURE
                  ? 'border-blue-600 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              System Analysis
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-6">
        {activeTab === Tab.FEED && (
          <div className="space-y-6">
            {/* Filters */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 space-y-4">
              <div className="flex flex-col md:flex-row gap-3">
                 <select 
                    value={selectedTopic}
                    onChange={(e) => setSelectedTopic(e.target.value as TopicFilter)}
                    className="flex-1 bg-gray-50 border border-gray-200 text-gray-700 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-2.5"
                 >
                   {Object.values(TopicFilter).map(topic => (
                     <option key={topic} value={topic}>{topic}</option>
                   ))}
                 </select>
                 <select 
                    value={selectedJournal}
                    onChange={(e) => setSelectedJournal(e.target.value as JournalFilter)}
                    className="flex-1 bg-gray-50 border border-gray-200 text-gray-700 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-2.5"
                 >
                   {Object.values(JournalFilter).map(journal => (
                     <option key={journal} value={journal}>{journal}</option>
                   ))}
                 </select>
                 <button
                  onClick={handleRefresh}
                  disabled={isFetching}
                  className="bg-blue-600 hover:bg-blue-700 text-white font-medium rounded-lg text-sm px-5 py-2.5 text-center flex items-center justify-center gap-2 disabled:opacity-50"
                 >
                   {isFetching ? (
                     <svg className="animate-spin h-4 w-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                   ) : (
                     <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                   )}
                   {isFetching ? 'Scanning...' : 'Fetch New'}
                 </button>
              </div>
              <p className="text-xs text-gray-400">
                * Fetching uses Google Search Grounding to find live papers from the web.
              </p>
            </div>

            {/* Paper List */}
            <div className="space-y-4">
              {papers.map(paper => (
                <PaperCard 
                  key={paper.id} 
                  paper={paper} 
                  onUpdate={handlePaperUpdate} 
                />
              ))}
            </div>

            {papers.length === 0 && (
              <div className="text-center py-10 text-gray-500">
                No papers found. Try adjusting filters or clicking Fetch New.
              </div>
            )}
          </div>
        )}

        {activeTab === Tab.ARCHITECTURE && (
          <ArchitectureInfo />
        )}
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Paper, AnalysisResponse } from "../types";

// Helper to get client (assumes user has selected key via window.aistudio or we use a provided one)
const getClient = () => {
  const apiKey = process.env.API_KEY; // In a real app, this comes from env. 
  // For this generated artifact, we rely on the injected process.env.API_KEY 
  // or the user interaction handles it in the main flow.
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

/**
 * Simulates the "Crawler" by using Google Search Grounding to find recent papers.
 */
export const fetchLatestPapers = async (topic: string, journal: string): Promise<Paper[]> => {
  const client = getClient();
  const query = `Find 3 most recent scientific research papers published in ${journal === 'All Journals' ? 'major psychiatry journals' : journal} about "${topic === 'All Topics' ? 'psychiatry' : topic}" published in the last month. 

  Return the result as a JSON array where each object has these fields: 
  - title (string)
  - journal (string)
  - date (string)
  - url (string)
  - abstract (string, brief summary)

  Important: Return ONLY the JSON array. Do not use markdown formatting.`;

  try {
    const response = await client.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: query,
      config: {
        tools: [{ googleSearch: {} }],
        // NOTE: responseMimeType and responseSchema are NOT supported when using googleSearch tool.
        // We must parse the text response manually.
      }
    });

    let text = response.text;
    if (!text) return [];

    // Clean up potential markdown code blocks (e.g., ```json ... ```)
    text = text.replace(/```json|```/g, '').trim();

    let rawPapers: any[] = [];
    try {
        rawPapers = JSON.parse(text);
    } catch (e) {
        console.error("Failed to parse JSON from search result", text);
        return [];
    }

    if (!Array.isArray(rawPapers)) {
        return [];
    }

    // Transform into our Paper type
    return rawPapers.map((p: any, index: number) => ({
      id: `gen-${Date.now()}-${index}`,
      title: p.title || 'Untitled',
      journal: p.journal || 'Unknown Journal',
      date: p.date || 'Recent',
      url: p.url || '#',
      abstract: p.abstract || '',
      isAnalyzed: false
    }));
  } catch (error) {
    console.error("Error fetching papers:", error);
    throw error;
  }
};

