export const PaperCard: React.FC<Props> = ({ paper, onUpdate }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [isSaved, setIsSaved] = useState(false);

  // Check if paper is already saved in localStorage on mount and hydrate if needed
  useEffect(() => {
    try {
      const savedRaw = localStorage.getItem('psych_brain_saved_papers');
      if (savedRaw) {
        const savedPapers: Paper[] = JSON.parse(savedRaw);
        const savedPaper = savedPapers.find(p => p.id === paper.id);

        if (savedPaper) {
          setIsSaved(true);
          // If the saved version has analysis but the current prop doesn't (e.g. on refresh), restore it.
          if (savedPaper.isAnalyzed && !paper.isAnalyzed) {
            onUpdate(savedPaper);
          }
        }
      }
    } catch (e) {
      console.error("Error reading from local storage", e);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [paper.id]);

  const handleAnalyze = async () => {
    setLoading(true);
    setError('');
    try {
      const analysis = await analyzePaperWithAI(paper);
      const updatedPaper = {
        ...paper,
        ...analysis,
        isAnalyzed: true
      };
      onUpdate(updatedPaper);

      // If it was already saved, update the saved version with the new analysis content immediately
      if (isSaved) {
        updateLocalStorage(updatedPaper);
      }
    } catch (err) {
      setError('Analysis failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const updateLocalStorage = (paperToSave: Paper) => {
    try {
      const savedRaw = localStorage.getItem('psych_brain_saved_papers');
      let savedPapers: Paper[] = savedRaw ? JSON.parse(savedRaw) : [];

      // Ensure we replace any old version with the new fully analyzed version
      savedPapers = savedPapers.filter(p => p.id !== paperToSave.id);
      savedPapers.push(paperToSave);

      localStorage.setItem('psych_brain_saved_papers', JSON.stringify(savedPapers));
    } catch (e) {
      console.error("Error updating local storage", e);
    }
  };

  const handleToggleSave = () => {
    try {
      const savedRaw = localStorage.getItem('psych_brain_saved_papers');
      let savedPapers: Paper[] = savedRaw ? JSON.parse(savedRaw) : [];

      if (isSaved) {
        // Remove from storage
        savedPapers = savedPapers.filter(p => p.id !== paper.id);
        setIsSaved(false);
      } else {
        // Add current state to storage. 
        // This 'paper' object already contains analysis fields if isAnalyzed is true.
        savedPapers = savedPapers.filter(p => p.id !== paper.id);
        savedPapers.push(paper);
        setIsSaved(true);
      }
      localStorage.setItem('psych_brain_saved_papers', JSON.stringify(savedPapers));
    } catch (e) {
      console.error("Error toggling save", e);
      alert("Unable to save to local storage.");
    }
  };

  const handleCopy = () => {
    if (!paper.isAnalyzed) return;

    const text = `
【${paper.journal}】${paper.titleZh || paper.title}
刊登日期：${paper.date}
連結：${paper.url}

一言以蔽之：
${paper.summary}

PICO 分析：
- P (Population): ${paper.pico?.p}
- I (Intervention): ${paper.pico?.i}
- C (Comparison): ${paper.pico?.c}
- O (Outcome): ${paper.pico?.o}

臨床效益：
${paper.utility}

標籤：${paper.tags?.map(t => `#${t}`).join(' ')}
    `.trim();

    navigator.clipboard.writeText(text).then(() => {
      alert('分析內容已複製到剪貼簿！');
    }).catch(err => {
      console.error('Failed to copy text: ', err);
      alert('複製失敗，請手動選取。');
    });
  };

  const journalColor = (journal: string) => {
    if (journal.includes('NEJM')) return 'bg-blue-100 text-blue-800';
    if (journal.includes('Lancet')) return 'bg-red-100 text-red-800';
    if (journal.includes('JAMA')) return 'bg-purple-100 text-purple-800';
    return 'bg-gray-100 text-gray-800';
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden mb-4 transition-all hover:shadow-md">
      {/* Card Header */}
      <div className="flex items-center justify-between px-4 py-3 border-b border-gray-100 bg-gray-50/50">
        <div className="flex items-center gap-3">
          <span className={`px-2 py-1 rounded text-xs font-bold ${journalColor(paper.journal)}`}>
            {paper.journal}
          </span>
          <span className="text-xs text-gray-400 font-medium flex items-center gap-1">
            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
            {paper.date}
          </span>
        </div>
        <div className="flex items-center gap-3 text-xs font-medium text-gray-500">
          {paper.isAnalyzed && (
            <button 
              onClick={handleCopy}
              className="flex items-center gap-1 hover:text-blue-600 transition-colors"
              title="Copy analysis to clipboard"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3"></path>
              </svg>
              複製
            </button>
          )}
          <button 
            onClick={handleToggleSave}
            className={`flex items-center gap-1 transition-colors ${isSaved ? 'text-blue-600' : 'hover:text-blue-600'}`}
            title={isSaved ? "Remove from bookmarks" : "Save full analysis to local bookmarks"}
          >
            <svg className="w-4 h-4" fill={isSaved ? "currentColor" : "none"} stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z"></path>
            </svg>
            {isSaved ? '已收藏' : '收藏'}
          </button>
          <a href={paper.url} target="_blank" rel="noopener noreferrer" className="hover:text-blue-600 flex items-center gap-1">
            PubMed <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"></path></svg>
          </a>
        </div>
      </div>

      <div className="p-4 md:p-5">
        {/* Titles */}
        <h3 className="text-gray-400 text-sm font-light mb-1 leading-snug">
          {paper.title}
        </h3>

        {paper.isAnalyzed && paper.titleZh ? (
           <h2 className="text-xl md:text-2xl font-bold text-gray-800 mb-4 leading-tight">
            {paper.titleZh}
          </h2>
        ) : (
          <div className="mt-2 mb-4">
             <h2 className="text-xl font-bold text-gray-300">
               Waiting for analysis...
             </h2>
          </div>
        )}

        {/* Action Button if not analyzed */}
        {!paper.isAnalyzed && (
          <div className="bg-blue-50 border border-blue-100 rounded-lg p-4 flex flex-col items-center justify-center gap-2">
            <p className="text-sm text-blue-600 mb-2">Analysis, Translation & PICO Extraction</p>
            <button 
              onClick={handleAnalyze} 
              disabled={loading}
              className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-full text-sm font-medium transition-colors flex items-center gap-2 disabled:opacity-50"
            >
              {loading ? (
                <>
                  <svg className="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                  Analyzing with Gemini...
                </>
              ) : (
                <>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
                  Run AI Analysis
                </>
              )}
            </button>
            {error && <p className="text-red-500 text-xs mt-1">{error}</p>}
          </div>
        )}

        {/* Analysis Result */}
        {paper.isAnalyzed && (
          <div className="space-y-4 animate-fade-in">
            {/* Summary Box */}
            <div className="bg-blue-50 border-l-4 border-blue-500 p-4 rounded-r-lg">
              <h4 className="text-blue-900 font-bold text-sm mb-1">One-line Summary</h4>
              <p className="text-blue-800 text-base font-medium">
                {paper.summary}
              </p>
            </div>

            {/* PICO Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <div className="bg-gray-50 p-3 rounded border border-gray-100">
                <span className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Population</span>
                <p className="text-sm text-gray-700">{paper.pico?.p}</p>
              </div>
              <div className="bg-gray-50 p-3 rounded border border-gray-100">
                <span className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Intervention</span>
                <p className="text-sm text-gray-700">{paper.pico?.i}</p>
              </div>
              <div className="bg-gray-50 p-3 rounded border border-gray-100">
                <span className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Comparison</span>
                <p className="text-sm text-gray-700">{paper.pico?.c}</p>
              </div>
              <div className="bg-green-50 p-3 rounded border border-green-100">
                <span className="text-xs font-bold text-green-600 uppercase tracking-wider block mb-1">Outcome</span>
                <p className="text-sm text-green-800 font-medium">{paper.pico?.o}</p>
              </div>
            </div>

            {/* Utility & Tags */}
            <div className="bg-amber-50 p-3 rounded-lg border border-amber-100 flex flex-col md:flex-row gap-4 items-start md:items-center">
              <div className="flex-1">
                <span className="flex items-center gap-1 text-amber-700 font-bold text-sm mb-1">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                  Clinical Utility
                </span>
                <p className="text-sm text-amber-800">{paper.utility}</p>
              </div>
              <div className="flex gap-2 flex-wrap">
                {paper.tags?.map(tag => (
                  <span key={tag} className="px-2 py-1 bg-white text-gray-600 text-xs rounded border border-gray-200">
                    #{tag}
                  </span>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export interface Paper {
  id: string;
  title: string;
  journal: string;
  date: string;
  url?: string;
  abstract?: string;
  // AI Generated fields
  titleZh?: string;
  summary?: string;
  pico?: {
    p: string;
    i: string;
    c: string;
    o: string;
  };
  utility?: string;
  tags?: string[];
  isAnalyzed?: boolean;
}

export interface AnalysisResponse {
  titleZh: string;
  summary: string;
  pico: {
    p: string;
    i: string;
    c: string;
    o: string;
  };
  utility: string;
  tags: string[];
}

export enum Tab {
  FEED = 'FEED',
  ARCHITECTURE = 'ARCHITECTURE'
}

export enum JournalFilter {
  ALL = 'All Journals',
  // Top Tier / General Medicine with Psych
  NEJM = 'NEJM',
  LANCET = 'The Lancet',
  JAMA = 'JAMA',

  // Psychiatry Q1/Q2
  WORLD_PSYCH = 'World Psychiatry',
  JAMA_PSYCH = 'JAMA Psychiatry',
  LANCET_PSYCH = 'Lancet Psychiatry',
  MOL_PSYCH = 'Molecular Psychiatry',
  AM_J_PSYCH = 'Am J Psychiatry',
  BIO_PSYCH = 'Biological Psychiatry',
  NATURE_NEURO = 'Nature Neuroscience',
  PSYCH_MED = 'Psychological Medicine',
  J_CLIN_PSYCH = 'J Clinical Psychiatry',
  BRIT_J_PSYCH = 'Brit J Psychiatry',
  SCHIZ_BULL = 'Schizophrenia Bulletin',
  NEUROPSYCHOPHARMACOLOGY = 'Neuropsychopharmacology',
  J_CPP = 'J Child Psychol Psychiatry',
  ACTA_PSYCH_SCAND = 'Acta Psychiatr Scand',
  J_AFFECT_DISORDERS = 'Journal of Affective Disorders'
}

export enum TopicFilter {
  ALL = 'All Topics',
  SCHIZOPHRENIA = 'Schizophrenia',
  DEPRESSION = 'Depression',
  BIPOLAR = 'Bipolar',
  ANXIETY = 'Anxiety',
  PTSD = 'PTSD',
  OCD = 'OCD',
  DISSOCIATION = 'Dissociation',
  ADDICTION = 'Addiction',
  PAIN = 'Pain',
  PSYCHOTHERAPY = 'Psychotherapy',
  SUICIDE = 'Suicide',
  CHILD_ADOLESCENT = 'Child & Adolescent'
}

import React, { useState, useEffect } from 'react';
import { INITIAL_PAPERS } from './constants';
import { Paper, Tab, JournalFilter, TopicFilter } from './types';
import { PaperCard } from './components/PaperCard';
import { ArchitectureInfo } from './components/ArchitectureInfo';
import { fetchLatestPapers } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.FEED);
  const [papers, setPapers] = useState<Paper[]>(INITIAL_PAPERS);
  const [selectedTopic, setSelectedTopic] = useState<TopicFilter>(TopicFilter.ALL);
  const [selectedJournal, setSelectedJournal] = useState<string>(JournalFilter.ALL);
  const [isFetching, setIsFetching] = useState(false);

  // Custom Journal Management
  const [customJournals, setCustomJournals] = useState<string[]>([]);
  const [newJournalInput, setNewJournalInput] = useState('');
  const [showJournalManager, setShowJournalManager] = useState(false);

  // Load custom journals and papers from localStorage
  useEffect(() => {
    const savedCustom = localStorage.getItem('psych_brain_custom_journals');
    if (savedCustom) {
      setCustomJournals(JSON.parse(savedCustom));
    }

    // Also try to load cached papers to keep state consistent across refreshes
    const savedPapers = localStorage.getItem('psych_brain_feed_cache');
    if (savedPapers) {
      // For simplicity, we just merge or use cached if they are fresher
      // setPapers(JSON.parse(savedPapers));
    }
  }, []);

  // Sync custom journals to storage
  useEffect(() => {
    localStorage.setItem('psych_brain_custom_journals', JSON.stringify(customJournals));
  }, [customJournals]);

  const handleAddJournal = () => {
    if (!newJournalInput.trim()) return;

    // Support batch import via comma
    const journalsToAdd = newJournalInput
      .split(',')
      .map(j => j.trim())
      .filter(j => j && !customJournals.includes(j) && !Object.values(JournalFilter).includes(j as JournalFilter));

    if (journalsToAdd.length > 0) {
      setCustomJournals(prev => [...prev, ...journalsToAdd]);
      setNewJournalInput('');
    }
  };

  const handleRemoveJournal = (journal: string) => {
    setCustomJournals(prev => prev.filter(j => j !== journal));
    if (selectedJournal === journal) {
      setSelectedJournal(JournalFilter.ALL);
    }
  };

  const handlePaperUpdate = (updatedPaper: Paper) => {
    setPapers(prev => {
      const newPapers = prev.map(p => p.id === updatedPaper.id ? updatedPaper : p);
      localStorage.setItem('psych_brain_feed_cache', JSON.stringify(newPapers));
      return newPapers;
    });
  };

  const handleRefresh = async () => {
    setIsFetching(true);
    try {
      const newPapers = await fetchLatestPapers(selectedTopic, selectedJournal);
      setPapers(prev => {
        const updated = [...newPapers, ...prev];
        // Limit to last 50 papers for performance
        const truncated = updated.slice(0, 50);
        localStorage.setItem('psych_brain_feed_cache', JSON.stringify(truncated));
        return truncated;
      });
    } catch (e) {
      alert("Failed to fetch new papers. Please ensure you have a valid API Key and quota.");
    } finally {
      setIsFetching(false);
    }
  };

  const currentDate = new Date().toLocaleDateString('zh-TW', { month: '2-digit', day: '2-digit' });

  // Combine built-in and custom journals
  const allAvailableJournals = [...Object.values(JournalFilter), ...customJournals];

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between mb-4">
            <div>
              <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Psychiatry Brain</h1>
              <p className="text-xs text-gray-500 font-medium mt-1">AI-Powered Research Intelligence</p>
            </div>
            <div className="flex items-center gap-2 text-xs text-gray-500 bg-gray-100 px-3 py-1.5 rounded-full">
               <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
               Updated: {currentDate}
            </div>
          </div>

          <div className="flex space-x-6 border-b border-gray-100">
            <button
              onClick={() => setActiveTab(Tab.FEED)}
              className={`pb-2 text-sm font-medium transition-colors border-b-2 ${
                activeTab === Tab.FEED
                  ? 'border-blue-600 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              Daily Feed
            </button>
            <button
              onClick={() => setActiveTab(Tab.ARCHITECTURE)}
              className={`pb-2 text-sm font-medium transition-colors border-b-2 ${
                activeTab === Tab.ARCHITECTURE
                  ? 'border-blue-600 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              System Analysis
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-6">
        {activeTab === Tab.FEED && (
          <div className="space-y-6">
            {/* Filters & Custom Journals Section */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 space-y-4">
              <div className="flex flex-col md:flex-row gap-3">
                 <select 
                    value={selectedTopic}
                    onChange={(e) => setSelectedTopic(e.target.value as TopicFilter)}
                    className="flex-1 bg-gray-50 border border-gray-200 text-gray-700 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-2.5"
                 >
                   {Object.values(TopicFilter).map(topic => (
                     <option key={topic} value={topic}>{topic}</option>
                   ))}
                 </select>
                 <select 
                    value={selectedJournal}
                    onChange={(e) => setSelectedJournal(e.target.value)}
                    className="flex-1 bg-gray-50 border border-gray-200 text-gray-700 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-2.5"
                 >
                   {allAvailableJournals.map(journal => (
                     <option key={journal} value={journal}>{journal}</option>
                   ))}
                 </select>
                 <button
                  onClick={handleRefresh}
                  disabled={isFetching}
                  className="bg-blue-600 hover:bg-blue-700 text-white font-medium rounded-lg text-sm px-5 py-2.5 text-center flex items-center justify-center gap-2 disabled:opacity-50"
                 >
                   {isFetching ? (
                     <svg className="animate-spin h-4 w-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                   ) : (
                     <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                   )}
                   {isFetching ? 'Scanning...' : 'Fetch New'}
                 </button>
              </div>

              <div className="pt-2 border-t border-gray-100 flex items-center justify-between">
                <button 
                  onClick={() => setShowJournalManager(!showJournalManager)}
                  className="text-xs font-medium text-blue-600 hover:text-blue-800 flex items-center gap-1"
                >
                  <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4"></path></svg>
                  {showJournalManager ? '收起期刊管理' : '管理自定義期刊 / 匯入'}
                </button>
                <p className="text-xs text-gray-400">
                  * 使用 Google Search 搜尋即時發表的論文。
                </p>
              </div>

              {showJournalManager && (
                <div className="p-3 bg-gray-50 rounded-lg border border-dashed border-gray-300 animate-fade-in">
                  <div className="flex gap-2 mb-3">
                    <input 
                      type="text"
                      placeholder="輸入期刊名稱（多個請用逗號隔開）"
                      value={newJournalInput}
                      onChange={(e) => setNewJournalInput(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && handleAddJournal()}
                      className="flex-1 bg-white border border-gray-200 text-sm rounded-lg p-2 focus:ring-blue-500 focus:border-blue-500"
                    />
                    <button 
                      onClick={handleAddJournal}
                      className="bg-gray-800 text-white text-xs px-4 py-2 rounded-lg hover:bg-black transition-colors"
                    >
                      新增 / 匯入
                    </button>
                  </div>

                  {customJournals.length > 0 ? (
                    <div className="flex flex-wrap gap-2">
                      {customJournals.map(j => (
                        <span key={j} className="flex items-center gap-1 px-2 py-1 bg-blue-100 text-blue-700 text-xs rounded-md border border-blue-200">
                          {j}
                          <button onClick={() => handleRemoveJournal(j)} className="hover:text-red-500">
                            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                          </button>
                        </span>
                      ))}
                    </div>
                  ) : (
                    <p className="text-[10px] text-gray-400 italic">尚未新增任何自定義期刊</p>
                  )}
                </div>
              )}
            </div>

            {/* Paper List */}
            <div className="space-y-4">
              {papers.map(paper => (
                <PaperCard 
                  key={paper.id} 
                  paper={paper} 
                  onUpdate={handlePaperUpdate} 
                />
              ))}
            </div>

            {papers.length === 0 && (
              <div className="text-center py-10 text-gray-500">
                No papers found. Try adjusting filters or clicking Fetch New.
              </div>
            )}
          </div>
        )}

        {activeTab === Tab.ARCHITECTURE && (
          <ArchitectureInfo />
        )}
      </main>
    </div>
  );
};

export default App;
